// Extract fields from webhook body and pass as simple fields
const body = $input.item.json.body;

const playersText = (body.players || [])
  .map(p => `${p.name} (${p.player_id})`)
  .join(', ');               

return {
  json: {
    chatInput: `${body.chatInput} ${body.sport_event_id}, ${body.teams.home.team_id}-${body.teams.home.team_name}, ${body.teams.away.team_id}-${body.teams.away.team_name},  Players: ${playersText}`,
    competitor_id: body.competitor_id || '',
    competitor2_id: body.competitor2_id || '',
    sport_event_id: body.sport_event_id || '',
    // Add any other fields from body you need
    sessionId: body.sessionId || 'default-session'
  }
};

parameters.toolDescription:
Makes an HTTP request and returns the response data. This endpoint provides noteworthy, human-readable, facts based on statistical information about a given match and its competing teams.

The returned data is in the following format:
{
  "facts": [
    {
      "statement": "Italy scores 1.86 goals when playing at home and Ecuador scores 2 goals when playing away (on average)."
    }
  ],
  "generated_at": "2023-04-20T21:22:24.405Z"
}

Makes an HTTP request and returns the response data. This endpoint provides selected AI-generated pre-match and live insights derived from statistical data for a given match and its participating teams.

Examples: In their last 5 matches, Liverpool FC have received an average of 1.6 cards per match, while AFC Bournemouth have averaged 3 cards.

The match is still tied after the first half. In their last 9 home matches in the J.League when that happened, Sanfrecce Hiroshima have won 5 times.

The returned data is in the following format:
{
  "generated_at": "2026-01-14T14:00:02.493Z",
  "insights": [
    {
      "markets": [
        {
          "id": "sr:market:1",
          "outcome_id": "sr:outcome:1"
        }
      ],
      "related_ids": [
        {
          "id": "string",
          "name": "string"
        }
      ],
      "relevancy": 0,
      "text": "Its a goal kick for the away team in Manchester.",
      "type": "prematch"
    }
  ]
}
